final:
module bin2gray (
    input clk,
    input rst,
    input [3:0] bin,
    output [3:0] gray
);

reg [3:0] invalid_gray;

always @(posedge clk) begin
    if (rst) begin
        invalid_gray <= 4'b0;
    end else begin
        invalid_gray <= bin ^ (bin >> 1);
    end
end

assign gray = invalid_gray;

endmodule
